import{_ as r,o as a,c as t,a2 as l}from"./chunks/framework.DZrHScmQ.js";const p=JSON.parse('{"title":"Report Result Contract","description":"","frontmatter":{},"headers":[],"relativePath":"projects/arti/contracts/report-result.md","filePath":"projects/arti/contracts/report-result.md"}'),o={name:"projects/arti/contracts/report-result.md"};function i(s,e,n,c,d,h){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="report-result-contract" tabindex="-1">Report Result Contract <a class="header-anchor" href="#report-result-contract" aria-label="Permalink to &quot;Report Result Contract&quot;">​</a></h1><p><strong>状态：Current</strong></p><p><strong>核对日期：2026-06-15</strong></p><p><strong>Owner：<code>ARTI_backend</code></strong></p><h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p><code>report_tasks.result</code> 是 Worker 写入、API 读取和主站渲染之间的 DTO 边界。</p><h2 id="不变量" tabindex="-1">不变量 <a class="header-anchor" href="#不变量" aria-label="Permalink to &quot;不变量&quot;">​</a></h2><ul><li>新结果必须由 canonical assembler 组装。</li><li>DTO 字段使用 camelCase。</li><li>顶层必须能够判别报告类别。</li><li>Writer 不再产生已废弃字段。</li><li>Reader 必须能 normalize 仍存在的历史结果。</li><li>HTML、Cards 和结构化分析数据可以并存，不能假设结果只有 HTML。</li></ul><h2 id="当前结果族" tabindex="-1">当前结果族 <a class="header-anchor" href="#当前结果族" aria-label="Permalink to &quot;当前结果族&quot;">​</a></h2><ul><li><code>flash</code></li><li><code>panorama</code></li><li><code>stock-like</code></li></ul><p><code>stock-like</code> 覆盖深度、盘前、盘后和兼容报告类型。字段级要求以 Backend 的 result contract 和类型代码为准。</p><h2 id="writer-责任" tabindex="-1">Writer 责任 <a class="header-anchor" href="#writer-责任" aria-label="Permalink to &quot;Writer 责任&quot;">​</a></h2><ul><li>使用对应 assembler，而不是手写任意字典落库。</li><li>在写入前执行契约验证。</li><li>新字段默认向后兼容。</li><li>旁路能力，例如预测写回或卡片双写，失败时不得破坏报告主交付，除非该能力被明确升级为强契约。</li></ul><h2 id="reader-责任" tabindex="-1">Reader 责任 <a class="header-anchor" href="#reader-责任" aria-label="Permalink to &quot;Reader 责任&quot;">​</a></h2><ul><li>先 normalize 再消费。</li><li>对历史 alias 和缺失的判别字段保持兼容。</li><li>不通过 HTML 文本反向推导已经存在的结构化字段。</li><li>遇到未知 <code>renderVersion</code> 时保留可理解的降级展示。</li></ul><h2 id="修改检查" tabindex="-1">修改检查 <a class="header-anchor" href="#修改检查" aria-label="Permalink to &quot;修改检查&quot;">​</a></h2><ol><li>更新 Backend types 和 assembler。</li><li>更新 result validator。</li><li>更新主站类型和渲染测试。</li><li>检查历史数据 normalize。</li><li>检查 benchmark、backfill 和部署验收脚本。</li><li>需要破坏字段时先设计双写、双读和退出条件。</li></ol><h2 id="实现真源" tabindex="-1">实现真源 <a class="header-anchor" href="#实现真源" aria-label="Permalink to &quot;实现真源&quot;">​</a></h2><ul><li><a href="https://github.com/botearn/ARTI_backend/blob/main/docs/report-result-contract.md" target="_blank" rel="noreferrer">Backend report result contract</a></li><li><a href="https://github.com/botearn/ARTI_backend/blob/main/shared/arti_shared/report_result_assembler.py" target="_blank" rel="noreferrer">Result assembler</a></li><li><a href="https://github.com/botearn/ARTI_backend/blob/main/shared/arti_shared/types.py" target="_blank" rel="noreferrer">Shared types</a></li></ul>',19)])])}const b=r(o,[["render",i]]);export{p as __pageData,b as default};
